const clientMappings = {
  "abc@probeps.com": {
    clientId: "client-001",
    clientName: "ABC Pediatrics"
  },
  "sunrise@probeps.com": {
    clientId: "client-002",
    clientName: "Sunrise Clinic"
  }
};

