  const client = clientMappings[communicationAddress];

  if (client) {
    item.json.clientId = client.clientId;
    item.json.clientName = client.clientName;
  } else {
    item.json.clientId = "unknown";
    item.json.clientName = "Unknown Client";
  }

}

return $input.all();

