const item = $input.first();

const category =
  item.json.classification.category;

const agents =
  item.json.agentRepository;

const matchingAgents =
  agents.filter(
    agent =>
      agent.specialization === category &&
      agent.available === true
  );

if (matchingAgents.length === 0) {

  item.json.assignment = {
    assignedTo: null,
    assignedAgent: null,
    assignmentMode: "UNASSIGNED",
    reason: "No available specialist found"
  };

  return [
    {
      json: item.json
    }
  ];
}

const selectedAgent =
  matchingAgents.reduce(
    (least, current) =>
      current.activeTickets <
      least.activeTickets
        ? current
        : least
  );

item.json.assignment = {

  assignedTo:
    selectedAgent.agentId,

  assignedAgent:
    selectedAgent.name,

  assignmentMode:
    "CATEGORY_LOAD_BALANCED",

  assignedAt:
    new Date().toISOString()
};

selectedAgent.activeTickets++;

return [
  {
    json: item.json
  }
];

