const item = $input.first();

const priority =
item.json.classification.priority;

let responseHours;
let resolutionHours;

if(priority === "High")
{
    responseHours = 2;
    resolutionHours = 8;
}
else if(priority === "Medium")
{
    responseHours = 8;
    resolutionHours = 24;
}
else
{
    responseHours = 24;
    resolutionHours = 72;
}

const now = new Date();

const responseDueAt =
new Date(
    now.getTime() +
    responseHours * 60 * 60 * 1000
);

const resolutionDueAt =
new Date(
    now.getTime() +
    resolutionHours * 60 * 60 * 1000
);

item.json.sla.responseDueAt =
responseDueAt.toISOString();

item.json.sla.resolutionDueAt =
resolutionDueAt.toISOString();

return [
{
    json: item.json
}
];

